            if (budget.alertLevel === 'waspada') {
              cardStyle = "bg-yellow-50 border-yellow-300 text-yellow-800";
              barStyle = "bg-yellow-500";
              icon = "ΓÜá∩╕Å";
            } else if (budget.alertLevel === 'bahaya') {
              cardStyle = "bg-red-50 border-red-300 text-red-800";
              barStyle = "bg-red-500";
              icon = "≡ƒÜ¿";
