'use client';

import { useState } from 'react';
import { approveExpense, rejectExpense } from '@/lib/expense-actions';
import { formatRupiah } from '@/lib/utils';

export default function ApprovalClient({ pendingExpenses }: { pendingExpenses: Record<string, any>[] }) {
  const [isProcessing, setIsProcessing] = useState<string | null>(null);

const handleAction = async (id: string, action: 'approve' | 'reject') => {
    if (!confirm(`Apakah Anda yakin ingin ${action === 'approve' ? 'MENYETUJUI' : 'MENOLAK'} pengeluaran ini?`)) return;

    setIsProcessing(id);
    try {
      if (action === 'approve') {
        await approveExpense(id);
        alert('Pengeluaran disetujui!');
      } else {
        await rejectExpense(id);
        alert('Pengeluaran ditolak!');
      }
      window.location.reload();
    } catch (err: any) {
      alert('Gagal: ' + err.message);
    } finally {
      setIsProcessing(null);
    }
  };

  return (
    <div className="flex-1 p-10 bg-soft-gray overflow-y-auto h-full">
      <div className="mb-6">
        <h1 className="text-3xl font-bold text-yellow-600">PERSETUJUAN PENGELUARAN (OWNER)</h1>
        <p className="text-gray-500 mt-1">Daftar beban operasional bernilai besar (&gt; Rp 5.000.000) yang tertahan dan wajib di-ACC Owner.</p>
      </div>

      <div className="bg-white rounded-xl shadow-sm border border-yellow-200 overflow-hidden">
        <div className="bg-yellow-50 p-4 border-b border-yellow-200">
          <h2 className="font-bold text-yellow-800 flex items-center gap-2">
            <span>≡ƒ¢í∩╕Å</span> Menunggu Persetujuan ({pendingExpenses.length})
          </h2>
        </div>
        <table className="w-full text-left border-collapse">
          <thead>
            <tr className="bg-white border-b border-gray-100 text-gray-500 text-sm">
              <th className="p-4 font-medium">Tanggal</th>
              <th className="p-4 font-medium">Kategori & Keterangan</th>
              <th className="p-4 font-medium">Nominal Request</th>
              <th className="p-4 font-medium text-right">Aksi Owner</th>
            </tr>
          </thead>
          <tbody>
            {pendingExpenses.map((exp) => (
              <tr key={exp.id} className="border-b border-gray-50 hover:bg-gray-50/50 transition">
                <td className="p-4 text-sm text-gray-600">
                  {new Date(exp.created_at).toLocaleString('id-ID')}
                </td>
                <td className="p-4">
                  <p className="font-bold text-gray-800">{exp.category}</p>
                  <p className="text-sm text-gray-500">{exp.description}</p>
                </td>
                <td className="p-4 font-bold text-yellow-600 text-lg">
                  {formatRupiah(exp.amount)}
                </td>
                <td className="p-4 text-right">
                  <div className="flex gap-2 justify-end">
                    <button 
                      onClick={() => handleAction(exp.id, 'reject')}
                      disabled={isProcessing === exp.id}
                      className="bg-white border border-red-200 text-red-500 hover:bg-red-50 px-3 py-2 rounded-lg text-sm font-bold disabled:opacity-50 transition"
                    >
                      Tolak
                    </button>
                    <button 
                      onClick={() => handleAction(exp.id, 'approve')}
                      disabled={isProcessing === exp.id}
                      className="bg-[#00875A] text-white hover:bg-green-700 px-4 py-2 rounded-lg text-sm font-bold disabled:opacity-50 transition shadow-sm"
                    >
                      {isProcessing === exp.id ? '...' : 'Setujui (Approve)'}
                    </button>
                  </div>
                </td>
              </tr>
            ))}
            {pendingExpenses.length === 0 && (
              <tr>
                <td colSpan={4} className="p-8 text-center text-gray-400 font-medium">Tidak ada antrian persetujuan saat ini.</td>
              </tr>
            )}
          </tbody>
        </table>
      </div>
    </div>
  );
}

'use client';

import { useState } from 'react';
import { addInventoryItem, updateInventoryItem, deleteInventoryItem } from '@/lib/inventory-actions';

type InventoryItem = {
  id: string;
  name: string;
  category: string;
  stock: number;
  unit: string;
  threshold: number;
  unitPrice: number;
  status: string;
};

export default function InventoryClient({ initialItems }: { initialItems: InventoryItem[] }) {
  const [items, setItems] = useState<InventoryItem[]>(initialItems);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingItem, setEditingItem] = useState<InventoryItem | null>(null);
  const [isProcessing, setIsProcessing] = useState(false);

  const handleOpenModal = (item?: InventoryItem) => {
    if (item) {
      setEditingItem(item);
    } else {
      setEditingItem(null);
    }
    setIsModalOpen(true);
  };

  const handleCloseModal = () => {
    setIsModalOpen(false);
    setEditingItem(null);
  };

  const handleSubmit = async (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    setIsProcessing(true);
    const formData = new FormData(e.currentTarget);

    try {
      if (editingItem) {
        await updateInventoryItem(editingItem.id, formData);
        // Optimistic UI update could be added here, but revalidatePath will refresh data.
      } else {
        await addInventoryItem(formData);
      }
      handleCloseModal();
      window.location.reload(); // Simple refresh to get new server data after revalidate
    } catch (error) {
      alert('Terjadi kesalahan saat menyimpan data');
    } finally {
      setIsProcessing(false);
    }
  };

  const handleDelete = async (id: string) => {
    if (confirm('Apakah Anda yakin ingin menghapus barang ini?')) {
      setIsProcessing(true);
      try {
        await deleteInventoryItem(id);
        window.location.reload();
      } catch (error) {
        alert('Gagal menghapus data');
      } finally {
        setIsProcessing(false);
      }
    }
  };

  return (
    <div className="flex-1">
      <div className="flex justify-between items-center mb-6">
        <h1 className="text-3xl font-bold text-[#00875A]">INVENTARIS</h1>
        <button 
          onClick={() => handleOpenModal()}
          className="bg-[#00875A] text-white px-4 py-2 rounded-lg font-bold shadow-md hover:bg-green-700 transition"
        >
          + Tambah Barang
        </button>
      </div>

      <div className="bg-white rounded-xl shadow-sm border border-gray-100 overflow-hidden">
        <table className="w-full text-left border-collapse">
          <thead>
            <tr className="bg-gray-50 border-b border-gray-100 text-gray-500 text-sm">
              <th className="p-4 font-medium">Nama Barang</th>
              <th className="p-4 font-medium">Kategori</th>
              <th className="p-4 font-medium">Stok</th>
              <th className="p-4 font-medium">Biaya/Unit</th>
              <th className="p-4 font-medium">Status</th>
              <th className="p-4 font-medium text-right">Aksi</th>
            </tr>
          </thead>
          <tbody>
            {items.map((item) => (
              <tr key={item.id} className="border-b border-gray-50 hover:bg-gray-50/50 transition">
                <td className="p-4 font-bold">{item.name}</td>
                <td className="p-4 text-gray-600">{item.category}</td>
                <td className="p-4 font-bold">{item.stock} <span className="text-gray-500 font-normal">{item.unit}</span></td>
                <td className="p-4 text-gray-600">Rp {item.unitPrice.toLocaleString('id-ID')}</td>
                <td className="p-4">
                  <span className={`px-3 py-1 rounded-full text-xs font-bold ${
                    item.status === 'Aman' ? 'bg-green-100 text-green-700' : 'bg-red-100 text-red-700'
                  }`}>
                    {item.status}
                  </span>
                </td>
                <td className="p-4 text-right">
                  <button onClick={() => handleOpenModal(item)} className="text-[#00875A] font-bold text-sm hover:underline mr-4">Edit</button>
                  <button onClick={() => handleDelete(item.id)} className="text-red-500 font-bold text-sm hover:underline">Hapus</button>
                </td>
              </tr>
            ))}
            {items.length === 0 && (
              <tr>
                <td colSpan={6} className="p-8 text-center text-gray-400">Belum ada data bahan baku.</td>
              </tr>
            )}
          </tbody>
        </table>
      </div>

      {isModalOpen && (
        <div className="fixed inset-0 bg-black/50 backdrop-blur-sm z-50 flex items-center justify-center p-4">
          <div className="bg-white rounded-xl shadow-xl w-full max-w-lg overflow-hidden">
            <div className="p-6 border-b border-gray-100 flex justify-between items-center bg-gray-50">
              <h2 className="text-xl font-bold text-[#00875A]">
                {editingItem ? 'Edit Bahan Baku' : 'Tambah Bahan Baku Baru'}
              </h2>
              <button onClick={handleCloseModal} className="text-gray-400 hover:text-gray-600 font-bold text-xl">&times;</button>
            </div>

            <form onSubmit={handleSubmit} className="p-6 space-y-4">
              <div>
                <label className="block text-sm font-bold text-gray-700 mb-1">Nama Barang</label>
                <input required type="text" name="name" defaultValue={editingItem?.name} className="w-full border border-gray-300 px-4 py-2 rounded-lg focus:ring-2 focus:ring-[#00875A] outline-none" />
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="block text-sm font-bold text-gray-700 mb-1">Kategori</label>
                  <select name="category" defaultValue={editingItem?.category || 'Bahan Baku'} className="w-full border border-gray-300 px-4 py-2 rounded-lg focus:ring-2 focus:ring-[#00875A] outline-none">
                    <option>Bahan Baku</option>
                    <option>Packaging</option>
                    <option>Bahan Tambahan</option>
                  </select>
                </div>
                <div>
                  <label className="block text-sm font-bold text-gray-700 mb-1">Satuan Dasar</label>
                  <select name="unit" defaultValue={editingItem?.unit || 'Gram'} className="w-full border border-gray-300 px-4 py-2 rounded-lg focus:ring-2 focus:ring-[#00875A] outline-none">
                    <option>Gram</option>
                    <option>Kg</option>
                    <option>ml</option>
                    <option>Liter</option>
                    <option>Pcs</option>
                  </select>
                </div>
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="block text-sm font-bold text-gray-700 mb-1">Kuantitas Stok</label>
                  <input required type="number" step="0.01" name="stock" defaultValue={editingItem?.stock} className="w-full border border-gray-300 px-4 py-2 rounded-lg focus:ring-2 focus:ring-[#00875A] outline-none" />
                </div>
                <div>
                  <label className="block text-sm font-bold text-gray-700 mb-1">Batas Minimum (Alert)</label>
                  <input required type="number" step="0.01" name="threshold" defaultValue={editingItem?.threshold} className="w-full border border-gray-300 px-4 py-2 rounded-lg focus:ring-2 focus:ring-[#00875A] outline-none" />
                </div>
              </div>

              <div>
                <label className="block text-sm font-bold text-gray-700 mb-1">Harga per Satuan (Rp)</label>
                <input required type="number" name="unitPrice" defaultValue={editingItem?.unitPrice} className="w-full border border-gray-300 px-4 py-2 rounded-lg focus:ring-2 focus:ring-[#00875A] outline-none" />
              </div>

              <div className="pt-4 flex gap-3">
                <button type="button" onClick={handleCloseModal} className="flex-1 bg-gray-100 text-gray-600 py-3 rounded-lg font-bold hover:bg-gray-200 transition">Batal</button>
                <button type="submit" disabled={isProcessing} className="flex-1 bg-[#00875A] text-white py-3 rounded-lg font-bold hover:bg-green-700 transition disabled:opacity-50">
                  {isProcessing ? 'Menyimpan...' : 'Simpan Data'}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
}

import { Sidebar } from "@/components/layout/Sidebar";
import { cookies } from "next/headers";

export default async function DashboardLayout({
  children,
}: {
  children: React.ReactNode;
}) {
  const cookieStore = await cookies();
  const sessionValue = cookieStore.get('hemat_session')?.value;

  let activeUser = "Gania K.";
  let activeRole = "owner";
  if (sessionValue && sessionValue.startsWith('{')) {
    try {
      const parsed = JSON.parse(sessionValue);
      if (parsed.name) activeUser = parsed.name;
      if (parsed.role) activeRole = parsed.role;
    } catch (e) {}
  }

  return (
    <div className="flex h-screen overflow-hidden bg-soft-gray">
      <Sidebar activeUser={activeUser} activeRole={activeRole} />
      <div className="flex-1 overflow-hidden flex flex-col">
        {children}
      </div>
    </div>
  );
}

'use client';

import { useState } from 'react';
import { requestVoid } from '@/lib/pos-actions';
import { formatRupiah } from '@/lib/utils';

export default function HistoryClient({ history }: { history: Record<string, any>[] }) {
  const [isProcessing, setIsProcessing] = useState<string | null>(null);

const handleVoid = async (id: string) => {
    if (!confirm('Apakah Anda yakin ingin mengajukan pembatalan (Void) untuk transaksi ini?')) return;

    setIsProcessing(id);
    try {
      await requestVoid(id);
      alert('Berhasil diajukan! Menunggu persetujuan Manajer.');
      window.location.reload();
    } catch (err: any) {
      alert('Gagal: ' + err.message);
    } finally {
      setIsProcessing(null);
    }
  };

  return (
    <div className="flex-1 p-10 bg-soft-gray overflow-y-auto h-full">
      <div className="mb-6 flex justify-between items-center">
        <div>
          <h1 className="text-3xl font-bold text-[#00875A]">RIWAYAT KASIR</h1>
          <p className="text-gray-500 mt-1">Daftar transaksi yang telah dilakukan. Ajukan void jika terjadi kesalahan.</p>
        </div>
      </div>

      <div className="bg-white rounded-xl shadow-sm border border-gray-100 overflow-hidden">
        <table className="w-full text-left border-collapse">
          <thead>
            <tr className="bg-gray-50 border-b border-gray-100 text-gray-500 text-sm">
              <th className="p-4 font-medium">No. Order / Waktu</th>
              <th className="p-4 font-medium">Item Pesanan</th>
              <th className="p-4 font-medium">Total Harga</th>
              <th className="p-4 font-medium">Metode / Status</th>
              <th className="p-4 font-medium text-right">Aksi</th>
            </tr>
          </thead>
          <tbody>
            {history.map((trx) => (
              <tr key={trx.id} className="border-b border-gray-50 hover:bg-gray-50/50 transition">
                <td className="p-4">
                  <p className="font-bold text-gray-800">{trx.order_number}</p>
                  <p className="text-xs text-gray-400">{new Date(trx.created_at).toLocaleString('id-ID')}</p>
                </td>
                <td className="p-4">
                  <ul className="text-sm text-gray-600 list-disc pl-4">
                    {trx.transaction_items?.map((item: Record<string, any>, idx: number) => (
                      <li key={idx}>
                        {item.quantity}x {item.menus?.menu_name || 'Item'}
                      </li>
                    ))}
                  </ul>
                </td>
                <td className="p-4 font-bold text-[#00875A]">
                  {formatRupiah(trx.total_amount)}
                </td>
                <td className="p-4">
                  <p className="text-sm font-bold text-gray-700 capitalize">{trx.payment_method}</p>
                  <p className={`text-xs mt-1 font-bold ${
                    trx.status === 'completed' ? 'text-green-500' :
                    trx.status === 'pending_void' ? 'text-yellow-500' : 'text-red-500'
                  }`}>
                    {trx.status === 'pending_void' ? 'Menunggu Void' : trx.status.toUpperCase()}
                  </p>
                </td>
                <td className="p-4 text-right">
                  {trx.status === 'completed' && (
                    <button 
                      onClick={() => handleVoid(trx.id)}
                      disabled={isProcessing === trx.id}
                      className="bg-white border border-red-200 text-red-500 hover:bg-red-50 px-3 py-1 rounded-md text-sm font-bold disabled:opacity-50 transition"
                    >
                      {isProcessing === trx.id ? '...' : 'Request Void'}
                    </button>
                  )}
                </td>
              </tr>
            ))}
            {history.length === 0 && (
              <tr>
                <td colSpan={5} className="p-8 text-center text-gray-400 font-medium">Belum ada transaksi.</td>
              </tr>
            )}
          </tbody>
        </table>
      </div>
    </div>
  );
}

