export async function payDebt(id: string, amount: number) {
  await new Promise((resolve) => setTimeout(resolve, 800));

  const debt = globalDb.debts.find(d => d.id === id);
  if (!debt) return { success: false, error: 'Tagihan tidak ditemukan' };

  if (debt.status === 'Lunas') return { success: false, error: 'Tagihan sudah lunas' };

  debt.paidAmount += amount;

  if (debt.paidAmount >= debt.amount) {
    debt.paidAmount = debt.amount;
    debt.status = 'Lunas';
  }

  // Jika Hutang, maka bayar pakai Total Kas. (Untuk kesederhanaan simulasi, kita lewati update Kas. Nanti dihubungkan ke Kas).

  revalidatePath('/debts');

  return { success: true, message: `Berhasil mencatat pembayaran sejumlah Rp ${amount.toLocaleString('id-ID')}` };
}

import { processOrder } from './pos-actions';

const DB_NAME = 'hemat-pos-db';
const STORE_NAME = 'offline_transactions';

export function openDB(): Promise<IDBDatabase> {
  return new Promise((resolve, reject) => {
    const request = indexedDB.open(DB_NAME, 1);

    request.onerror = () => reject(request.error);
    request.onsuccess = () => resolve(request.result);

    request.onupgradeneeded = (event: any) => {
      const db = event.target.result;
      if (!db.objectStoreNames.contains(STORE_NAME)) {
        db.createObjectStore(STORE_NAME, { keyPath: 'id', autoIncrement: true });
      }
    };
  });
}

export async function saveOfflineTransaction(cartItems: Record<string, any>[], paymentMethod: string, totalAmount: number) {
  const db = await openDB();
  return new Promise<void>((resolve, reject) => {
    const transaction = db.transaction(STORE_NAME, 'readwrite');
    const store = transaction.objectStore(STORE_NAME);

    const data = {
      cartItems,
      paymentMethod,
      totalAmount,
      timestamp: new Date().toISOString()
    };

    const request = store.add(data);
    request.onsuccess = () => resolve();
    request.onerror = () => reject(request.error);
  });
}

export async function getOfflineTransactions(): Promise<any[]> {
  const db = await openDB();
  return new Promise((resolve, reject) => {
    const transaction = db.transaction(STORE_NAME, 'readonly');
    const store = transaction.objectStore(STORE_NAME);
    const request = store.getAll();

    request.onsuccess = () => resolve(request.result);
    request.onerror = () => reject(request.error);
  });
}

export async function deleteOfflineTransaction(id: number) {
  const db = await openDB();
  return new Promise<void>((resolve, reject) => {
    const transaction = db.transaction(STORE_NAME, 'readwrite');
    const store = transaction.objectStore(STORE_NAME);
    const request = store.delete(id);

    request.onsuccess = () => resolve();
    request.onerror = () => reject(request.error);
  });
}

export async function syncOfflineTransactions() {
  try {
    const pendingTxs = await getOfflineTransactions();
    if (pendingTxs.length === 0) return;

    for (const tx of pendingTxs) {
      try {
        // Panggil Server Action untuk memproses ulang
        const result = await processOrder(tx.cartItems, tx.paymentMethod, tx.totalAmount);

        if (result.success) {
          // Jika sukses disinkronkan, hapus dari IndexedDB
          await deleteOfflineTransaction(tx.id);
        }
      } catch (err) {

        // Biarkan di IndexedDB untuk dicoba lagi nanti
      }
    }
  } catch (error) {

  }
}

